import { useMemo } from 'react';
import { useSort } from '@features/Sort/hooks/useSort';
import { useCategoryFilter } from '@features/Filter/hooks/useCategoryFilter';
export const useProductsParams = (params) => {
    const { sortBy, order } = useSort();
    const { category } = useCategoryFilter();
    return useMemo(() => ({
        sortBy,
        order,
        category,
        limit: params?.limit,
        skip: params?.skip,
        page: params?.currentPage,
    }), [sortBy, order, category, params?.limit, params?.skip, params?.currentPage]);
};
